#include <stdio.h>
#include <assert.h>

int firstOne(int row[], int low, int high) {
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if ((mid == 0 || row[mid - 1] == 0) && row[mid] == 1)
            return mid;
        else if (row[mid] == 0)
            return firstOne(row, mid + 1, high);
        else
            return firstOne(row, low, mid - 1);
    }
    return -1; 
}

int maxOneRow(int mat[][1001], int m, int n) {
    int maxones = 0, row = 0;
    for(int i = 0; i < m; i++) {
        int ones = n - firstOne(mat[i], 0, n - 1);
        if(ones > maxones) {
            maxones = ones;
            row = i;
        }
    }
    return row + 1; 
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    assert(1 <= n && n <= 1001);
    assert(1 <= m && m <= 1001);

    int mat[1001][1001];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &mat[i][j]);
            assert(mat[i][j] == 0 || mat[i][j] == 1);
        }
    }

    printf("%d\n", maxOneRow(mat, n, m));

    return 0;
}

